#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N, K; scanf("%" PRId64 " %" PRId64, &N, &K);
        int64_t cnt1 = (N + 2) / 3;
        int64_t cnt2 = (N + 1) / 3;
        int64_t ans;
        if(K <= cnt1){
            ans = 1 + (K - 1) * 3;
        } else if(K <= cnt1 + cnt2){
            int64_t k2 = K - cnt1;
            ans = 2 + (k2 - 1) * 3;
        } else {
            int64_t k0 = K - cnt1 - cnt2;
            ans = 3 * k0;
        }
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

