#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        cnt1 = (N + 2) // 3
        cnt2 = (N + 1) // 3
        if K <= cnt1:
            ans = 1 + (K - 1) * 3
        elif K <= cnt1 + cnt2:
            k2 = K - cnt1
            ans = 2 + (k2 - 1) * 3
        else:
            k0 = K - cnt1 - cnt2
            ans = 3 * k0
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

